// GET /api/posts?limit=20&after=<cursor>

// --- Cursor helpers ---

// Encode a {created_at, id} pair into an opaque base64 string.
function encodeCursor(row) {
    const payload = JSON.stringify({
        created_at: row.created_at instanceof Date
            ? row.created_at.toISOString()
            : row.created_at,
        id: row.id,
    });
    return Buffer.from(payload, 'utf8').toString('base64url');
}

// Decode an opaque cursor back into {created_at, id}.
// Throws on anything malformed so the caller can return a 400.
function decodeCursor(cursor) {
    let parsed;
    try {
        const json = Buffer.from(cursor, 'base64url').toString('utf8');
        parsed = JSON.parse(json);
    } catch (err) {
        throw new Error('Cursor is not valid base64-encoded JSON');
    }

    if (
        parsed === null ||
        typeof parsed !== 'object' ||
        typeof parsed.id === 'undefined' ||
        typeof parsed.created_at === 'undefined'
    ) {
        throw new Error('Cursor is missing required fields');
    }

    // Validate created_at is a real timestamp.
    if (Number.isNaN(Date.parse(parsed.created_at))) {
        throw new Error('Cursor has an invalid created_at');
    }

    return { created_at: parsed.created_at, id: parsed.id };
}

// --- Endpoint ---

async function getPosts(req, res) {
    // Clamp limit to a sane range to protect the DB.
    let limit = parseInt(req.query.limit, 10) || 20;
    limit = Math.min(Math.max(limit, 1), 100);

    const params = [];
    let whereClause = 'WHERE published = true';

    // Only apply the cursor filter when an `after` cursor is supplied.
    if (typeof req.query.after === 'string' && req.query.after.length > 0) {
        let cursor;
        try {
            cursor = decodeCursor(req.query.after);
        } catch (err) {
            return res.status(400).json({ error: 'Invalid cursor' });
        }

        // Keyset predicate matching ORDER BY created_at DESC, id DESC.
        // Row tuple comparison: fetch rows strictly "after" the cursor.
        params.push(cursor.created_at, cursor.id);
        whereClause += ` AND (created_at, id) < ($1, $2)`;
    }

    // LIMIT N+1 trick: ask for one extra row to detect more pages.
    params.push(limit + 1);
    const limitParam = `$${params.length}`;

    const result = await db.query(
        `SELECT id, title, content, author_id, created_at
         FROM posts
         ${whereClause}
         ORDER BY created_at DESC, id DESC
         LIMIT ${limitParam}`,
        params
    );

    const rows = result.rows;
    const hasMore = rows.length > limit;

    // Drop the extra probe row before returning to the client.
    const posts = hasMore ? rows.slice(0, limit) : rows;

    const nextCursor = hasMore
        ? encodeCursor(posts[posts.length - 1])
        : null;

    res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,
            limit,
        },
    });
}

module.exports = { getPosts, encodeCursor, decodeCursor };
```

## Key implementation notes

- **Keyset predicate**: `(created_at, id) < ($1, $2)` is PostgreSQL row-value comparison. Because the sort is `created_at DESC, id DESC`, "next page" means rows that are *less than* the cursor tuple. Postgres compares lexicographically — `id` only breaks ties when `created_at` is equal — which exactly mirrors the `ORDER BY`. This makes the cursor stable even when many posts share the same `created_at`.
- **No OFFSET anywhere** — paging is done purely via the `WHERE` clause.
- **N+1 trick**: we request `limit + 1` rows. If we get them all, `hasMore = true` and we slice off the probe row; otherwise we're on the last page and `nextCursor` is `null`.
- **First page**: with no `after`, the cursor filter is skipped entirely.
- **Invalid cursors**: `decodeCursor` throws on bad base64, bad JSON, missing fields, or an unparseable date → caught and returned as `400`.
- **`base64url`** avoids `+`/`/`/`=` characters that need URL-encoding in a query string. Plain `base64` works too if you prefer.
- I clamped `limit` to `[1, 100]` to prevent a client from requesting a huge page; drop or adjust that if not wanted.

### One thing to verify in your schema

For the keyset comparison to be both correct and fast, you want a composite index matching the sort:

```sql
CREATE INDEX idx_posts_published_keyset
    ON posts (created_at DESC, id DESC)
    WHERE published = true;
```

Without it, Postgres can still answer the query but may do a sort/scan, losing the performance benefit.

## Why cursor-based is superior here

1. **Consistent results under writes.** With offset pagination, if a new post is inserted (or one is deleted) between requests, every row shifts by one and the user sees duplicates or skips rows at page boundaries. A keyset cursor anchors to an actual row, so concurrent inserts/deletes don't corrupt the sequence.
2. **Constant-time deep pagination.** `OFFSET 100000` forces Postgres to generate and discard 100k rows on every request — cost grows linearly with page depth. The keyset `WHERE (created_at, id) < (...)` uses the index to jump straight to the starting point, so page 5000 costs the same as page 1.
3. **No expensive COUNT.** `SELECT COUNT(*)` on a large table scans many rows just to compute `totalPages`, which most feed-style UIs don't actually need. Removing it eliminates a second, often dominant, query cost.

The tradeoff: you lose random access to an arbitrary page number (no "jump to page 50") and exact total counts — both of which are rarely needed for an infinite-scroll / "load more" feed, which is the typical use case for a posts endpoint like this.

