## Cursor-Based Pagination Implementation

```javascript
// ─── Cursor Helpers ──────────────────────────────────────────────────────────

/**
 * Encodes a (created_at, id) pair into an opaque, URL-safe base64 cursor string.
 * base64url avoids '+', '/', '=' characters that would need percent-encoding in URLs.
 *
 * @param {Date|string} created_at
 * @param {number|string} id
 * @returns {string} base64url-encoded cursor
 */
function encodeCursor(created_at, id) {
    const payload = JSON.stringify({
        created_at: created_at instanceof Date ? created_at.toISOString() : created_at,
        id: String(id),
    });
    return Buffer.from(payload, 'utf8').toString('base64url');
}

/**
 * Decodes a cursor string back into its { created_at, id } components.
 * Returns null if the cursor is missing, malformed, or structurally invalid.
 *
 * @param {string} cursorStr
 * @returns {{ created_at: string, id: string } | null}
 */
function decodeCursor(cursorStr) {
    try {
        const json = Buffer.from(cursorStr, 'base64url').toString('utf8');
        const parsed = JSON.parse(json);

        // Structural validation — both fields must be present and non-empty.
        if (
            typeof parsed !== 'object'                    ||
            parsed === null                               ||
            typeof parsed.created_at !== 'string'        ||
            !parsed.created_at                           ||
            typeof parsed.id !== 'string'                ||
            !parsed.id                                   ||
            isNaN(Number(parsed.id))                     ||  // id must be numeric
            isNaN(Date.parse(parsed.created_at))             // created_at must be a valid date
        ) {
            return null;
        }

        return { created_at: parsed.created_at, id: parsed.id };
    } catch {
        // JSON.parse failure, base64 decode failure, etc.
        return null;
    }
}

// ─── Endpoint ────────────────────────────────────────────────────────────────

// GET /api/posts?limit=20&after=<cursor>
async function getPosts(req, res) {
    // ── 1. Parse & validate inputs ───────────────────────────────────────────

    const limit = Math.min(
        Math.max(parseInt(req.query.limit) || 20, 1),  // floor at 1
        100                                             // hard cap — protect the DB
    );

    let cursor = null;
    if (req.query.after !== undefined) {
        cursor = decodeCursor(req.query.after);
        if (cursor === null) {
            return res.status(400).json({
                error: 'Invalid cursor. The `after` parameter is malformed or expired.',
            });
        }
    }

    // ── 2. Build query ───────────────────────────────────────────────────────
    //
    // Fetch limit+1 rows so we can detect whether a next page exists without
    // an expensive COUNT(*). The extra row is never returned to the client.
    //
    // Compound row comparison:
    //   (created_at, id) < (cursor.created_at, cursor.id)
    //
    // PostgreSQL expands this to:
    //   created_at < cursor.created_at
    //   OR (created_at = cursor.created_at AND id < cursor.id)
    //
    // This is exactly "rows that come after the cursor in DESC sort order".

    let rows;

    if (cursor) {
        const result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
                AND (created_at, id) < ($1::timestamptz, $2::bigint)
              ORDER BY created_at DESC, id DESC
              LIMIT $3`,
            [cursor.created_at, cursor.id, limit + 1]
        );
        rows = result.rows;
    } else {
        // First page — no cursor filter at all.
        const result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
              ORDER BY created_at DESC, id DESC
              LIMIT $1`,
            [limit + 1]
        );
        rows = result.rows;
    }

    // ── 3. Apply the N+1 trick ───────────────────────────────────────────────

    const hasMore = rows.length > limit;
    const posts   = hasMore ? rows.slice(0, limit) : rows;   // never expose the +1 row

    // ── 4. Build next cursor from the last row we're actually returning ──────

    const lastPost   = posts.length > 0 ? posts[posts.length - 1] : null;
    const nextCursor = hasMore && lastPost
        ? encodeCursor(lastPost.created_at, lastPost.id)
        : null;

    // ── 5. Respond ───────────────────────────────────────────────────────────

    res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,  // null when on the last page
            limit,
        },
    });
}
```

